import { revalidatePath } from "next/cache";
import { NextResponse } from "next/server";
import { addProperty, getProperties } from "@/lib/cms-store";

export const runtime = "nodejs";

type PropertyPayload = {
  title?: string;
  type?: string;
  location?: string;
  price?: string;
  status?: string;
  imageUrl?: string;
  description?: string;
};

export async function GET() {
  const properties = await getProperties();
  return NextResponse.json({ properties });
}

export async function POST(request: Request) {
  try {
    const body = (await request.json()) as PropertyPayload;

    if (!body.title || !body.type || !body.location || !body.price) {
      return NextResponse.json(
        { error: "title, type, location and price are required." },
        { status: 400 }
      );
    }

    const property = await addProperty({
      title: body.title,
      type: body.type,
      location: body.location,
      price: body.price,
      status: body.status ?? "new launch",
      imageUrl:
        body.imageUrl ??
        "https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=1200&q=80",
      description: body.description ?? "No description added yet.",
    });

    revalidatePath("/");
    return NextResponse.json({ property }, { status: 201 });
  } catch {
    return NextResponse.json(
      { error: "Invalid JSON body for property creation." },
      { status: 400 }
    );
  }
}
