import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export type ProjectBanner = {
  id: string;
  projectName: string;
  title: string;
  subtitle: string;
  imageUrl: string;
  ctaLabel: string;
  ctaHref: string;
  updatedAt: string;
};

export type Property = {
  id: string;
  title: string;
  type: string;
  location: string;
  price: string;
  status: string;
  imageUrl: string;
  description: string;
  createdAt: string;
};

type CmsData = {
  banner: ProjectBanner;
  properties: Property[];
};

const dataDirectory = path.join(process.cwd(), "data");
const dataFile = path.join(dataDirectory, "cms.json");

const defaultData: CmsData = {
  banner: {
    id: "banner-default",
    projectName: "Rite Realty",
    title: "Find Premium Projects In Kurukshetra",
    subtitle:
      "Explore verified plots, villas, and commercial investments in top growth sectors.",
    imageUrl:
      "https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=1600&q=80",
    ctaLabel: "Explore Projects",
    ctaHref: "/projects/new-launch",
    updatedAt: new Date().toISOString(),
  },
  properties: [],
};

async function ensureDataFile() {
  await mkdir(dataDirectory, { recursive: true });

  try {
    await readFile(dataFile, "utf8");
  } catch {
    await writeFile(dataFile, JSON.stringify(defaultData, null, 2), "utf8");
  }
}

async function readCmsData() {
  await ensureDataFile();
  const raw = await readFile(dataFile, "utf8");
  return JSON.parse(raw) as CmsData;
}

async function writeCmsData(data: CmsData) {
  await ensureDataFile();
  await writeFile(dataFile, JSON.stringify(data, null, 2), "utf8");
}

export async function getLatestBanner() {
  const data = await readCmsData();
  return data.banner;
}

export async function updateLatestBanner(
  payload: Omit<ProjectBanner, "id" | "updatedAt">
) {
  const data = await readCmsData();
  const updatedBanner: ProjectBanner = {
    id: `banner-${Date.now()}`,
    updatedAt: new Date().toISOString(),
    ...payload,
  };

  const updatedData: CmsData = {
    ...data,
    banner: updatedBanner,
  };

  await writeCmsData(updatedData);
  return updatedBanner;
}

export async function getProperties() {
  const data = await readCmsData();
  return [...data.properties].sort((a, b) =>
    a.createdAt < b.createdAt ? 1 : -1
  );
}

export async function addProperty(
  payload: Omit<Property, "id" | "createdAt">
) {
  const data = await readCmsData();
  const newProperty: Property = {
    id: `property-${Date.now()}`,
    createdAt: new Date().toISOString(),
    ...payload,
  };

  const updatedData: CmsData = {
    ...data,
    properties: [newProperty, ...data.properties],
  };

  await writeCmsData(updatedData);
  return newProperty;
}
